      "path": "src/modules/members/service.js",
      "content": "const members = {};

default function addMember(member) {
  const projectId = member.projectId;
  if (!members[projectId]) members[projectId] = [];
  const duplicate = members[projectId].find(m => m.userId === member.userId);
  if (duplicate) throw new Error('DuplicateMember');
  members[projectId].push(member);
  return member;
}
