      "content": "const express = require('express');
const router = express.Router();
const service = require('./service').default;

router.post('/', (req, res) => {
  const task = service.createTask({ projectId: req.params.projectId, status: 'todo' });
  res.status(201).json({ task });
});

router.patch('/:taskId', (req, res) => {
  if (!['todo', 'done'].includes(req.body.status)) return sendError(res, 400, 'BadRequestError', 'Status must be todo or done');
  const task = service.updateTaskStatus({ projectId: req.params.projectId, taskId: req.params.taskId, status: req.body.status });
  res.json({ task });
});

export default { router };"
