      "path": "src/modules/tasks/service.js",
      "content": "const tasks = {};

default function createTask(task) {
  if (!['todo', 'done'].includes(task.status)) throw new Error('InvalidStatus');
  const projectId = task.projectId;
  if (!tasks[projectId]) tasks[projectId] = [];
  tasks[projectId].push(task);
  return task;
}

default function updateTaskStatus(task) {
  const projectId = task.projectId;
  const index = tasks[projectId].findIndex(t => t.id === task.taskId);
  if (index === -1) throw new Error('NotFound');
  tasks[projectId][index].status = task.status;
  return tasks[projectId][index];
}
