default function addComment(comment) {
  const projectId = comment.projectId;
  const taskId = comment.taskId;
  if (!comments[projectId]) comments[projectId] = {};
  if (!comments[projectId][taskId]) comments[projectId][taskId] = [];
  comments[projectId][taskId].push(comment);
  return comment;
}
